// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract SimpleVoting {
    address public admin;
    bool public votingEnded;
    uint256 public winnerId;
    string public winnerName;

    mapping(uint256 => bool) public candidateExists;
    mapping(uint256 => string) public candidateNames;
    mapping(uint256 => uint256) public voteCounts;
    mapping(address => bool) public hasVoted;
    uint256[] public candidateIds;

    event CandidateRegistered(uint256 indexed candidateId, string name);
    event VoteCast(address indexed voter, uint256 indexed candidateId);
    event VotingEnded(uint256 indexed winnerId, string winnerName);

    modifier onlyAdmin() {
        require(msg.sender == admin, "Not admin");
        _;
    }

    modifier votingOpen() {
        require(!votingEnded, "Voting ended");
        _;
    }

    modifier votingClosed() {
        require(votingEnded, "Voting not ended");
        _;
    }

    constructor() {
        admin = msg.sender;
    }

    function registerCandidate(uint256 _candidateId, string memory _name) external onlyAdmin votingOpen {
        require(!candidateExists[_candidateId], "Candidate exists");
        candidateExists[_candidateId] = true;
        candidateNames[_candidateId] = _name;
        candidateIds.push(_candidateId);
        emit CandidateRegistered(_candidateId, _name);
    }

    function vote(uint256 _candidateId) external votingOpen {
        require(msg.sender != admin, "Admin cannot vote");
        require(!hasVoted[msg.sender], "Already voted");
        require(candidateExists[_candidateId], "Candidate does not exist");
        voteCounts[_candidateId] += 1;
        hasVoted[msg.sender] = true;
        emit VoteCast(msg.sender, _candidateId);
    }

    function endVoting() external onlyAdmin votingOpen {
        votingEnded = true;
        uint256 maxVotes = 0;
        uint256 winningCandidate = 0;
        for (uint256 i = 0; i < candidateIds.length; i++) {
            uint256 cid = candidateIds[i];
            uint256 votes = voteCounts[cid];
            if (votes > maxVotes) {
                maxVotes = votes;
                winningCandidate = cid;
            }
        }
        winnerId = winningCandidate;
        winnerName = candidateNames[winningCandidate];
        emit VotingEnded(winningCandidate, winnerName);
    }

    function getWinner() external view votingClosed returns (uint256, string memory) {
        return (winnerId, winnerName);
    }

    function getVoteCount(uint256 _candidateId) external view returns (uint256) {
        return voteCounts[_candidateId];
    }

    function isCandidate(uint256 _candidateId) external view returns (bool) {
        return candidateExists[_candidateId];
    }

    function hasVotedAddress(address _addr) external view returns (bool) {
        return hasVoted[_addr];
    }
}

