pragma solidity ^0.8.x;

contract SimpleVoting {
    enum VotingStatus { Open, Closed }

    address public admin;
    mapping(uint256 => string) public candidates;
    mapping(address => bool) public voters;
    mapping(uint256 => uint256) public voteCounts;
    uint256 public totalCandidates;
    VotingStatus public votingStatus;

    event CandidateRegistered(uint256 candidateId, string name);
    event VoteCast(address voter, uint256 candidateId);
    event VotingEnded();

    constructor() {
        admin = msg.sender;
        votingStatus = VotingStatus.Open;
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "Only admin can call this function");
        _;
    }

    modifier votingOpen() {
        require(votingStatus == VotingStatus.Open, "Voting has ended");
        _;
    }

    modifier notVoted(address voter) {
        require(!voters[voter], "Already voted");
        _;
    }

    function registerCandidate(string memory name) external onlyAdmin {
        totalCandidates++;
        candidates[totalCandidates] = name;
        emit CandidateRegistered(totalCandidates, name);
    }

    function vote(uint256 candidateId) external votingOpen notVoted(msg.sender) {
        require(candidateId > 0 && candidateId <= totalCandidates, "Invalid candidate ID");
        voters[msg.sender] = true;
        voteCounts[candidateId]++;
        emit VoteCast(msg.sender, candidateId);
    }

    function endVoting() external onlyAdmin {
        require(votingStatus == VotingStatus.Open, "Voting has already ended");
        votingStatus = VotingStatus.Closed;
        emit VotingEnded();
    }

    function getWinningCandidate() external view returns (uint256) {
        require(votingStatus == VotingStatus.Closed, "Voting is still open");
        uint256 winningCandidateId = 0;
        uint256 highestVoteCount = 0;

        for (uint256 i = 1; i <= totalCandidates; i++) {
            if (voteCounts[i] > highestVoteCount) {
                highestVoteCount = voteCounts[i];
                winningCandidateId = i;
            }
        }

        return winningCandidateId;
    }
}

