contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }

    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public amount;
    State public state;

    event ContractCreated(address indexed buyer, address indexed seller, address indexed arbiter, uint256 amount);
    event ItemDelivered();
    event PaymentReleased();
    event DisputeResolved(address winner, uint256 amount);
    event Refunded();

    constructor(address _seller, address _arbiter) payable {
        require(_seller != address(0), "Seller address cannot be zero");
        require(_arbiter != address(0), "Arbiter address cannot be zero");
        require(msg.value > 0, "Amount must be greater than zero");

        buyer = msg.sender;
        seller = _seller;
        arbiter = _arbiter;
        amount = msg.value;
        state = State.Created;

        emit ContractCreated(buyer, seller, arbiter, amount);
    }

    modifier onlySeller() {
        require(msg.sender == seller, "Only seller can call this function");
        _;
    }

    modifier onlyBuyer() {
        require(msg.sender == buyer, "Only buyer can call this function");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == arbiter, "Only arbiter can call this function");
        _;
    }

    modifier inState(State expected) {
        require(state == expected, "Invalid state");
        _;
    }

    function markDelivered() external onlySeller inState(State.Created) {
        state = State.Delivered;
        emit ItemDelivered();
    }

    function releasePayment() external onlyBuyer inState(State.Delivered) {
        payable(seller).transfer(amount);
        state = State.Released;
        emit PaymentReleased();
    }

    function dispute() external onlyBuyer inState(State.Delivered) {
        state = State.Disputed;
    }

    function resolveDispute(address winner) external onlyArbiter inState(State.Disputed) {
        require(winner == buyer || winner == seller, "Winner must be either buyer or seller");
        payable(winner).transfer(amount);
        state = State.Released;
        emit DisputeResolved(winner, amount);
    }

    function refund() external onlyBuyer inState(State.Created) {
        payable(buyer).transfer(amount);
        state = State.Refunded;
        emit Refunded();
    }
}

