    bytes32 public constant USER_ROLE = keccak256("USER_ROLE");

    // Track roles using nested mapping (role => address => bool)
    mapping(bytes32 => mapping(address => bool)) private _roles;

    // Ensure at least one admin exists
    address[] private _admins;

    event RoleGranted(bytes32 role, address account);
    event RoleRevoked(bytes32 role, address account);

    modifier onlyAdmin() {
        require(hasRole(ADMIN_ROLE, msg.sender), "Only admins can perform this action");
        _;
    }

    // Admin (deployer) can grant and revoke roles
    function grantRole(bytes32 role, address account) public virtual {
        require(role != ADMIN_ROLE || hasRole(ADMIN_ROLE, msg.sender), "Cannot grant admin role to non-admin");
        require(account != address(0), "Account cannot be zero");

        _roles[role][account] = true;
        emit RoleGranted(role, account);

        if (role == ADMIN_ROLE) {
            _admins.push(account);
        }
    }

    function revokeRole(bytes32 role, address account) public virtual onlyAdmin {
        require(account != address(0), "Account cannot be zero");

        _roles[role][account] = false;
        emit RoleRevoked(role, account);

        if (role == ADMIN_ROLE && _admins.length > 1) {
            for (uint256 i = 0; i < _admins.length; i++) {
                if (_admins[i] != account) {
                    grantRole(ADMIN_ROLE, _admins[i]);
                    break;
                }
            }
        } else if (role == ADMIN_ROLE && _admins.length == 1) {
            grantRole(ADMIN_ROLE, address(0));
        }
    }

    // Implement modifier to check if caller has specific role
    function hasRole(bytes32 role, address account) public view returns (bool) {
        return _roles[role][account];
    }

    // Admin can renounce their own role
    function renounceRole(bytes32 role) public virtual onlyAdmin {
        revokeRole(role, msg.sender);
    }

    // Sample functions demonstrating different role requirements
    function managerOnlyFunction() public virtual {
        require(hasRole(MANAGER_ROLE, msg.sender), "Only managers can perform this action");
        // Function implementation...
    }

