        _setRole(ADMIN_ROLE, msg.sender);
    }

    function hasRole(bytes32 role, address account) internal view returns (bool) {
        return _roles[role][account];
    }

    function grantRole(bytes32 role, address account) public onlyAdmin {
        require(account != address(0), "Account cannot be zero");
        if (!hasRole(role, account)) {
            _setRole(role, account);
            emit RoleGranted(role, account);
        }
    }

    function revokeRole(bytes32 role, address account) public onlyAdmin {
        require(hasRole(role, account), "Account does not have the specified role");
        _removeRole(role, account);
        emit RoleRevoked(role, account);
    }

    function renounceRole(bytes32 role) public {
        require(hasRole(role, msg.sender), "Only admins can renounce their own role");
        _removeRole(role, msg.sender);
    }

    function _setRole(bytes32 role, address account) private {
        _roles[role][account] = true;
    }

    function _removeRole(bytes32 role, address account) private {
        require(hasRole(role, account), "Account does not have the specified role");
        _roles[role][account] = false;

        // Reassign role to another admin if possible
        bytes32[] memory roles = getRoles();
        for (uint256 i = 0; i < roles.length; i++) {
            address newAdmin = getRoleAdmin(roles[i]);
            if (newAdmin != address(0)) {
                _setRole(roles[i], newAdmin);
                emit RoleGranted(roles[i], newAdmin);
                break;
            }
        }
    }

    function getRoles() private returns (bytes32[] memory) {
        bytes32[] memory roles = new bytes32[](3);
        roles[0] = ADMIN_ROLE;
        roles[1] = MANAGER_ROLE;
        roles[2] = USER_ROLE;
        return roles;
    }

    function getRoleAdmin(bytes32 role) private returns (address) {
