contract Escrow {
    enum State { Created, Delivered, Released, Refunded, Disputed }
    event StateChanged(State indexed newState);
    event Deposit(address indexed buyer, uint256 amount);
    event Release(address indexed seller);
    event Refund(address indexed buyer);
    event Dispute(uint256 disputeId);

    address public buyer;
    address public seller;
    address public arbiter;
    uint256 public depositAmount;
    State public state = State.Created;
    uint256 public disputeId;

    modifier onlyBuyer() {
        require(msg.sender == buyer, "Not the buyer");
        _;
    }

    modifier onlySeller() {
        require(msg.sender == seller, "Not the seller");
        _;
    }

    modifier onlyArbiter() {
        require(msg.sender == arbiter, "Not the arbiter");
        _;
    }

    constructor(address _buyer, address _seller, address _arbiter) payable {
        require(_buyer != address(0), "Invalid buyer address");
        require(_seller != address(0), "Invalid seller address");
        require(_arbiter != address(0), "Invalid arbiter address");
        require(_buyer != _seller && _buyer != _arbiter && _seller != _arbiter, "Addresses must be unique");

        buyer = _buyer;
        seller = _seller;
        arbiter = _arbiter;
        depositAmount = msg.value;
        emit Deposit(buyer, depositAmount);
    }

    function markDelivered() external onlySeller {
        require(state == State.Created, "Invalid state");
        state = State.Delivered;
        emit StateChanged(State.Delivered);
    }

    function releasePayment() external onlyBuyer {
        require(state == State.Delivered, "Invalid state");
        state = State.Released;
        payable(seller).transfer(depositAmount);
        emit Release(seller);
    }

    function refund() external onlyBuyer {
        require(state == State.Created || state == State.Disputed, "Invalid state");
        if (state == State.Created) {
            state = State.Refunded;
            payable(buyer).transfer(depositAmount);
            emit Refund(buyer);
        } else {
            // Handle dispute resolution logic here
            // For simplicity, we'll just mark it as resolved
            state = State.Disputed;
            emit Dispute(disputeId++);
        }
    }

    function resolveDispute(uint256 _disputeId) external onlyArbiter {
        require(_disputeId == disputeId, "Invalid dispute ID");
        require(state == State.Disputed, "Invalid state");

        // Handle dispute resolution logic here
        // For simplicity, we'll just mark it as resolved and allocate funds to the buyer
        state = State.Released;
        payable(buyer).transfer(depositAmount);
        emit Release(buyer);
    }
}

