    function allocateFunds() public {
        require(msg.sender == arbiter, "Only the arbiter can allocate funds");

        if (state == State.Disputed) {
            state = State.Released;

            emit ContractStateChanged(state);
        }
    }

    event ContractStateChanged(State newState);
}
